import { useState, useEffect } from 'react';

// ── IMAGES ────────────────────────────────────────────
const IMGS = {
  headshot:    '/images/img-headshot-1.jpeg',
  headshot2:   '/images/img-headshot-2.jpeg',
  surgery:     '/images/img-surgery.jpeg',
  conference:  '/images/img-conference.jpeg',
